INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (19, 'NIKBA', 'nikba', 'blend hypnotic atmospheres with intricate sound design. Their distinctive style blends depth, intensity, and narrative fluidity, and their ever-evolving auditory experience transports listeners to new levels of consciousness that have yet to be mapped.', '/uploads/artist_images/artist-1756837050677-48665040.jpg', NULL, NULL, NULL, NULL, NULL, '2025-09-02T17:17:45.704Z', 17);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (18, 'URANTIA', 'urantia', 'aries of perception, as they blend hypnotic atmospheres with intricate sound design. Their distinctive style blends depth, intensity, and narrative fluidity, and their ever-evolving auditory experience transports listeners to new levels of consciousness that have yet to be mapped.', '/uploads/artist_images/artist-1756837025094-733007696.jpg', NULL, NULL, NULL, NULL, NULL, '2025-09-02T17:17:20.859Z', 24);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (8, 'PSYROOT', 'psyroot', '
Psyroot is the original project of Disektor,
a music producer, sound designer and creative coder
aiming to explore Psychedelic landscape
and multi core sonic extractions.
He is also the founder of Geometric Corruption records.
His unique deep soundscape connects the present moment
with ancient times through expanding the listener’s audio sensory
experience by unique sonic poetry
combining harmony and chaos.', '/uploads/artist_images/artist-1756836455399-153138043.jpg', 'https://www.instagram.com/psyroot.music/', 'https://soundcloud.com/psyrootmusic', 'https://www.instagram.com/psyroot.music/', NULL, 'https://web.facebook.com/simo.mansouri.5815', '2025-07-26T23:04:16.876Z', 19);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (20, 'KALIMBAWA', 'kalimbawa', 'Emerging from Sale, Morocco, Simo Alami is the mind behind KALIMBAWA, a darkpsy experimental trance project that journeys into the depths of consciousness. His music explores the idea that consciousness is the ultimate reality, continuously recreating itself to experience existence from infinite perspectives. Galaxies, planets, and humans are all manifestations of the same cosmic awareness.
Each track is a journey, a sonic ritual where themes and messages unfold through titles, textures, and immersive sound design. Produced as storytelling journeys, KALIMBAWA explores a style he calls cinematic darkpsy a fusion of heavy, fast kicks and bass with atmospheric layers and haunting ambiences, creating a narrative that pulls listeners into shadowed realms.
Through hypnotic rhythms and storytelli', '/uploads/artist_images/artist-1756837089380-777134458.jpg', NULL, NULL, NULL, NULL, NULL, '2025-09-02T17:18:36.376Z', 15);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (9, 'PSYNTAGM', 'psyntagm', '
Psyntagm brews in passion for music, stirred by a deep love of rhythm and a reverence to sound. 
Psyntagm is a sonic storyteller, whose journey began with jazz and world music. Before discovering psychedelic sounds in 2017.
Through carefully curated sets, he guides listeners on immersive, transformative journeys, using music as an alchemical tool to explore the depths of mind and soul.', '/uploads/artist_images/artist-1756836435947-271543638.jpg', 'https://www.instagram.com/psyntagm/', 'https://soundcloud.com/faissal-ghaleb', 'https://izuranrecords.bandcamp.com/', NULL, NULL, '2025-07-26T23:04:16.967Z', 18);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (15, 'BLACK PHILLIP', 'black-phillip', 'Enter the labyrinth.
Wear whatever you want—but not your mask.
Your music is a mental tomb. A perpetual spiral.
It doesn''t ease your pain—it spills the truth with violence.
A living narrative that crawls like worms under dead leaves.
You will feel it. Even if you don''t want to.', '/uploads/artist_images/artist-1756836769166-409136100.jpg', 'https://www.instagram.com/blackphillip93.22/', 'https://soundcloud.com/xblackphillipx', NULL, NULL, NULL, '2025-09-02T17:13:10.524Z', 7);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (14, 'J-MRGL', 'j-mrgl', 'JewishMRGL is a producer and DJ based in Tunisia, driven by a passion for creating unique sounds that bridge his artistic influences. His APC40''s live known for creating deep, atmospheric, and mentally stimulating sonic experiences. Their sets push the boundaries of perception, as they blend hypnotic atmospheres with intricate sound design. Their distinctive style blends depth, intensity, and narrative fluidity, and their ever-evolving auditory experience transports listeners to new levels of consciousness that have yet to be mapped.', '/uploads/artist_images/artist-1756836737619-41594272.jpg', 'https://www.instagram.com/jewishmrgl/', 'https://soundcloud.com/jewishmrgl', NULL, NULL, NULL, '2025-09-02T17:12:23.729Z', 14);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (13, 'ANSHAR', 'anshar', 'Anshar is the psycore, experimental music project
by Cris Salazar created in 2021
in which he tries to give a dark approach
with influences of ethnic music
from different regions of the world
as well as with touches of drone music/dark ambient music.', '/uploads/artist_images/artist-1756836556502-247252150.jpg', 'https://www.instagram.com/mad102094/', 'https://soundcloud.com/ansharmusic', NULL, NULL, 'https://web.facebook.com/cris.crz.37', '2025-09-02T17:09:53.496Z', 6);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (17, 'ASTREA', 'astrea', 'Astrea is a darkpsy DJ whose sets blend hypnotic rhythms, fast-paced energy, and deep psychedelic textures. With a passion for exploring the balance between light and darkness, she creates immersive journeys that guide listeners into altered states of consciousness. On stage, Astrea transforms music into a ritual, offering experiences that are both mystical and cathartic, connecting the crowd with deeper layers of themselves.', '/uploads/artist_images/artist-1756836960148-564158826.jpg', 'https://www.instagram.com/najouatadry?igsh=MWRwd2V1YmQ0c2pzbw==', 'https://on.soundcloud.com/1vmOxnS3qpN0KrcEYm', NULL, NULL, NULL, '2025-09-02T17:16:47.640Z', 5);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (30, 'zulmah', 'zulmah', 'Zułmah is an emerging talent from the shadows of Lebanon.

Rooted in dark psy and psycore, he shapes his music through distortion, tension and hypnotic rhythm, music that feels summoned rather than produced. His name, meaning “darkness", mirrors the aura at the core of his sound: a descent into the deeper layers of the psyche.

Influenced by mythic ideas of the void and the echoes that call from within it, Zułmah shapes each set as a passage between worlds, a controlled unraveling where listeners follow the pulse as if answering an ancient signal.', '/uploads/artist_images/artist-1764442860938-412152509.jpg', 'https://www.instagram.com/zulmah.wav?igsh=MTEyaTJycGg4bHpvZQ==', 'https://soundcloud.com/nicolanicolas2', NULL, NULL, NULL, '2025-11-29T18:01:12.524Z', 25);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (23, 'Dahūla', 'dahula', 'Dahūla shares his passion for electronic music, blending modern beats with echoes of his Middle Eastern heritage. Embark on a sonic journey that bridges the past and the future, where pulsating rhythms transport you through time and culture', '/uploads/artist_images/artist-1759701677037-528806892.jpeg', 'https://www.instagram.com/dahula_sertsounds?igsh=eGZseGMzYzU3b2ox', 'https://on.soundcloud.com/XRsGjh4s6Ky5IsP4SZ', NULL, NULL, 'https://www.facebook.com/share/1CWKbpGqFb/', '2025-10-05T21:01:48.377Z', 11);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (21, 'Chilllight', 'chilllight', 'Nour Mahfoud Born in Casablanca, Morocco, Nour Mahfoud began his musical path with guitar, later embracing bass and the traditional Oud. In 2015, he discovered psychedelic music, a turning point that revealed his true direction.

For Nour, music is more than sound—it’s a portal to the unconscious, a language of the soul. His work blends chaotic beats, haunting melodies, and melancholic harmonies to explore human emotion, inner conflict, and transformation.

Through his art, he invites listeners to dive deep, confront their shadows, and find beauty in both darkness and light.', '/uploads/artist_images/artist-1759296172621-896296748.jpeg', 'https://www.instagram.com/chill.light?utm_source=ig_web_button_share_sheet&igsh=ZDNlZDc0MzIxNw==', 'https://soundcloud.com/chill-light', 'https://chilllight.bandcamp.com/', NULL, 'https://www.facebook.com/nour.mahfoud.9', '2025-10-01T04:23:17.248Z', 8);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (27, 'gyn-x', 'gyn-x', 'GYN-X
(Darkpsy / Experimental Psytrance)

Dark psychedelic project of Cem Berkman from Izmir, Turkey 🇹🇷

A lifelong devotee of electronic sound, Cem’s musical path began with guitar at 17—but his true voice emerged when he encountered the limitless realms of psychedelic music. Since 2015, under the alias Gyn-X, he has crafted immersive, high-voltage soundscapes that channel emotion through distortion and chaos through rhythm.

His sonic universe fuses deep frequencies, surreal atmospheres, and sharp textures designed to bend perception and ignite the subconscious.', '/uploads/artist_images/artist-1764442791407-398246929.jpg', 'https://www.instagram.com/gyn.x/', 'https://soundcloud.com/gyn-x', 'https://gyn-x.bandcamp.com/', NULL, 'https://web.facebook.com/gynxpage?_rdc=1&_rdr#', '2025-11-29T18:00:03.008Z', 13);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (22, 'Cosmic Silence', 'cosmic-silence', 'Cosmic Silence is a musical project born in Mexico City, led by Rodrigo Gudiño aka "Maleficaevm" and Claudia Piñon aka "Urantia". They have experimented with dark rhythms and atmospheres full of mysticism. Their music is characterized by being psychedelic and out of the ordinary.', '/uploads/artist_images/artist-1759701565632-865065708.jpeg', 'https://www.instagram.com/rasibu_999?igsh=NDQxdjMyYWhrN25v', 'https://on.soundcloud.com/0OLzKMjyxJMS2R6BHc', NULL, NULL, 'https://www.facebook.com/share/1Ft7dFfuEe/', '2025-10-05T21:00:52.107Z', 9);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (7, 'SKO', 'sko', 'Mouhcine aka Sko began his journey into the realms
of dark psychedelic music in 2012 at his first rave party,
where the music, atmosphere, and vibe immediately captivated him.
After countless party adventures with friends,
he started DJing in 2015, initially playing dark forest tunes.
His musical exploration eventually led him to discover his true passion
for dark psychedelic and psycore music.
Inspired by this deep connection,
he began producing his own tracks in 2020.
And in 2024, he took a major step forward
by founding his own label, Izuran Records.', '/uploads/artist_images/artist-1759712982273-536152740.jpeg', 'https://www.instagram.com/sko__art/', 'https://soundcloud.com/sko-artworks', 'https://izuranrecords.bandcamp.com/', NULL, 'https://web.facebook.com/Skomotions/', '2025-07-26T23:04:16.784Z', 22);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (25, 'M O R P H O S I S', 'm-o-r-p-h-o-s-i-s', 'Morphosis is an experimental psycore project forged by Niketh Acharya . A chaotic blend of high-BPM psychedelic destruction, industrial textures, and mind-warping atmospheres. Focused on pushing boundaries and dissolving structure, Morphosis channels dark energy into ritualistic sound journeys.
Fusing elements of darkpsy, glitchcore, noise, and abstract sound design, this project is a living organism, constantly mutating, always unpredictable. Morphosis is more than music. It''s a dissection of consciousness through extreme sonic architecture.', '/uploads/artist_images/artist-1760817381760-65492693.jpeg', NULL, 'https://soundcloud.com/morphosisdark', NULL, NULL, 'https://www.instagram.com/morphosis.live?utm_source=ig_web_button_share_sheet&igsh=ZDNlZDc0MzIxNw==', '2025-10-18T18:56:45.278Z', 16);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (28, 'rasibu', 'rasibu', 'rasibu Born in the heart of Mexico City in 2016, this project is raw, chaotic, and dark these are words that can define this project.Resumed in 2024 Rasibu comes with a renewed style, fresher and more interesting sounds.', '/uploads/artist_images/artist-1764442814960-885710904.jpg', 'https://www.instagram.com/rasibu_999?igsh=NDQxdjMyYWhrN25v', 'https://soundcloud.com/rasibu', NULL, NULL, NULL, '2025-11-29T18:00:25.805Z', 20);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (16, 'AKUMA', 'akuma', 'Daniel Luiz, also known as AkUmA, is a music producer specialized in the experimental ambient genre, which involves dark elements, intense atmospheres, and a unique aesthetic. Born in Anápolis, Daniel has always been fascinated by the darker side of music and sought to express his deepest emotions through sound art.
With an innovative approach, Daniel began experimenting with samples, sound textures, and advanced production techniques to create ecological and atmospheric soundscapes. His meticulousness in the studio and attention to detail quickly made him a skilled producer.
Daniel has collaborated with a variety of artists within the genre, from underground musicians to big names in the electronic scene. His ability to capture the essence of experimental electronic music and translate it', '/uploads/artist_images/artist-1756836858915-746813281.jpg', 'https://www.instagram.com/akuma_live333?igsh=MTdmNTd5dTNkMWlrNg==', 'https://soundcloud.com/akumaaa', 'https://akumalive333.bandcamp.com/', NULL, '', '2025-09-02T17:15:45.836Z', 2);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (31, 'Amaranth', 'amaranth', 'Amaranth is an experimental darkpsy project from Switzerland, blending (semi-)modular synthesizers, drum samples, and distorted vocal recordings to craft a deep, meditative journey.

Drawing influence from a wide variety of genres, Amaranth is always looking to explore uncharted territories and to carve her own path through the jungle of electronic music.

Amaranth also expresses her unique vision through her alternative project Amaryllis, where she explores creative freedom beyond conventional genre
boundaries.', '/uploads/artist_images/artist-1769474939152-883397516.jpeg', '', 'https://soundcloud.com/amaranth_a', 'https://www.instagram.com/amaranth__amaryllis/', NULL, 'https://www.facebook.com/amandine.chatellard', '2026-01-26T23:49:01.292Z', 4);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (32, 'Dark Lotus', 'dark-lotus', 'Vitor Felix is the mind behind the Dark Lotus Project.

He had his first contact with eletronic music at the age of 14 years old attending underground rave parties. At 16, he started Djing and had his first experience with psytrance in 1999 at the age of 18 years old, rapidly achieving 8 hour long performing dj sets that soon after turned into 12 or even 24 hours long.

In 2017 felt the need to go further and began studiyng music prodution, mix and master. At the same time he continued profounding his knowledge and interest in meditation and acestrial rituals,
hypnosis and mind consciousness thru mind control hacks. This was also the year he started the Abstract Meditation Crew along with Saadhuk.

In 2019 Vitor turned his skills into action and began the Dark Lotus project by creating mus', '/uploads/artist_images/artist-1769474981069-26700621.jpeg', 'https://www.instagram.com/dark_lotus_live/', 'https://soundcloud.com/dark_lotus_music', NULL, NULL, 'https://www.facebook.com/DarkLotusLive', '2026-01-26T23:49:56.190Z', 10);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (33, 'Lilith', 'lilith', 'Lilith is an ancient spirit that represents the third energy above man and woman, the union between masculine and feminine, whose figure appears in multiple myths from Mesopotamian to Jewish Mythology and Astrology. Through music, she channels this intense transformative love frequency that transcends expectations and traditional roles in society. She purges the shadow emotions and brings in the light, with a message that love is the ultimate answer to human suffering. While also holding up a mirror to those who are afraid to face themselves. She builds up intricate soundscapes and glitchy breaks, with interesting sound design, implementing meditative elements into high bpm tracks. Though her journey has just begun, she has the drive to transform herself in the art-form of experimental dan', '/uploads/artist_images/artist-1769475001931-124292426.jpeg', 'https://www.instagram.com/liliana_lilithu/', 'https://soundcloud.com/blckmoonlilith', NULL, NULL, NULL, '2026-01-26T23:50:24.134Z', 12);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (26, 'AKURRA', 'akurra', 'Akurra is a dark psychedelic music project originating from Western Australia.
Beginning music at an early age with guitar, original influences came from Metal, Punk and Prog Rock. After making bands and performing in this scene, interest in electronic and computer music came after a discovery of infinite sonic possibly with machines.

Now experimenting with different mediums Akurra uses many creative tools from analog synthesis to live field recordings to draw inspiration and channel his own expression into the work. This is a personal release of energy.

The result is fast, hard, dark psychedelic trance with synthetic machine type leads supported by organically collected atmospheres presented in ways to evoke internal thought, stimulate imagination and sometimes cause confusion.
Although', '/uploads/artist_images/artist-1764442776712-940934515.jpg', 'https://www.instagram.com/akurra_audio', 'https://soundcloud.com/akurra_audio', 'https://akurra.bandcamp.com/', NULL, 'https://web.facebook.com/akurra.audio?_rdc=1&_rdr#', '2025-11-29T17:59:41.953Z', 3);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (29, 'silent movement', 'silent-movement', 'Silent Movement
Genre: Forest, Dark Psy, Psychedelic Trance
Founded: Summer of 2016
Role: U.S. Label Director for Tripura Yantra Records; Member of Absolut Shit Records; Founder of RLPS Productions

Silent Movement is a versatile and influential artist within the psychedelic trance and electronic music scenes, known for crafting deep, hypnotic soundscapes that transport listeners into mystical, otherworldly realms. Since its formation in the summer of 2016, Silent Movement has gained global recognition, blending dark psy and forest trance to create transformative auditory experiences.', '/uploads/artist_images/artist-1764442835351-251611459.jpg', 'https://www.instagram.com/silent_movementmusic?igsh=MTFyNDhidXJ4ZXZhZw==', 'https://soundcloud.com/silent-movement', 'https://silentmovement.bandcamp.com/', NULL, 'https://www.facebook.com/share/18BHw1ToNw/', '2025-11-29T18:00:46.389Z', 21);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (24, 'Stendhalizer', 'stendhalizer', 'Khalil Alias Stendhalizer is a sonic explorer whose musical journey began in the depths of extreme sound. Initially rooted in the world of metal as a guitarist, his passion for intense, high-energy music naturally led him to push boundaries further, this time behind the decks. Since 2019, he has forged a distinct identity as a DJ, specializing in HiTech and Psycore.

Driven by a desire to create a powerful and transcendent experience, Stendhalizer channels the raw energy of his metal origins into electronic sets that are as aggressive as they are intricate. His performances are more than just music, they are immersive journeys designed to stir the subconscious, challenge perception, and guide listeners through deep introspective states.

With each set, Stendhalizer aims to captivate and ov', '/uploads/artist_images/artist-1760817336682-964691271.jpeg', 'https://www.instagram.com/k_a_y_2_3?utm_source=ig_web_button_share_sheet&igsh=ZDNlZDc0MzIxNw==', 'https://soundcloud.com/stendhalizer', NULL, NULL, 'https://web.facebook.com/khalilsellaoui', '2025-10-18T18:55:39.347Z', 23);
INSERT INTO "artists" ("id", "name", "slug", "description", "image_url", "instagram", "soundcloud", "bandcamp", "linktree", "facebook", "created_at", "display_order") VALUES (36, '3PL7VEN', '3pl7ven', '3PL7VEN is a forward-thinking darkpsy artist delivering powerful, experimental, and dark-oriented productions. Blending diverse styles and tempos, the project creates immersive sonic experiences driven by deep basslines, hypnotic rhythms, and high-energy structures across a wide BPM range. Through contrasts between tension and flow, darkness and transcendence, 3PL7VEN has developed a distinctive and evolving musical identity.

Welcome to 3PL7VEN, where the essence of sound thrives.', '/uploads/artist_images/artist-1770087827150-820202017.jpg', 'https://www.instagram.com/3pl7ven/', 'https://soundcloud.com/3pl7-777', NULL, 'https://astroqodelabs.com/', NULL, '2026-02-03T02:03:50.004Z', 0);

