INSERT INTO "events" ("id", "name", "slug", "description", "image_url", "date", "end_date", "location", "lineup", "ticket_price", "early_bird_price", "early_bird_end_date", "second_phase_price", "second_phase_end_date", "last_phase_price", "display_date", "status", "created_at", "featured") VALUES (4, 'IZURAN GATHERING FIRST EDITION', 'izuran-gathering-first-edition', '✨ Finally, the ground opens ✨
Izuran’s first gathering is coming!
Ready to sound the gate 🎶
Not upward, but inward 🌀

🪬You are not invited to attend.
You are called to remember.
In the ancient language of the Amazigh.Not through words but through music.
To unite, free by blood and spirit 🩸

🪞This is not a performance.
We gather not to entertain!
But to tear the veil with sound.
To let the dark devour the mask.
To celebrate earth and ancestry.
To dissolve the boundary, between body and land.
Sound and silence. Self and tribe. Root and star.

💫 Join us.
Dance your soul out.
Let the rhythm rot what was never true.
Enter the ground not to flee the dark! But to bear its seeds 🌹🖤🎶🌓.', '/uploads/event_images/event-1750933713491-115273428.jpg', '2025-08-01T23:00:00.000Z', '2025-08-02T23:00:00.000Z', 'Secret Location, barrage rouidat', '@breako.subterfuge.nomisa ,@xianzai ,@psyroot.music ,@aratri ,@blind_ox ,@sko__art ,@psyntagm ', '', '30', '2025-06-27T22:00:00.000Z', '40', '2025-07-29T22:00:00.000Z', '50', 'August 2-3, 2025 • 10hrs', 'completed', '2025-06-26T09:30:37.689Z', FALSE);

