INSERT INTO "products" ("id", "name", "slug", "description", "image_url", "price", "currency", "category", "product_type", "artist_name", "stock_level", "is_new_release", "cmi_product_id", "paypal_product_id", "digital_file_url", "created_at", "updated_at", "archived") VALUES (5, 'T-Shirt IZuran', 'tshirt-izuran', 'A black short-sleeve t-shirt bearing the same radiant gold sigil front and center, with a smaller version of the same symbol printed on the left chest area. The design flows like molten metal, adding an elemental and powerful energy to a clean-cut streetwear piece. Ideal for everyday wear while maintaining bold visual identity.', '/uploads/product_images/product-1769477094092-590192120.webp', '30.00', 'USD', 'merch', 'physical', '', 50, FALSE, '', '', NULL, '2025-07-26T18:25:05.807Z', NULL, FALSE);
INSERT INTO "products" ("id", "name", "slug", "description", "image_url", "price", "currency", "category", "product_type", "artist_name", "stock_level", "is_new_release", "cmi_product_id", "paypal_product_id", "digital_file_url", "created_at", "updated_at", "archived") VALUES (4, 'izuran Hoodie down', 'izuran-hoodie-down', 'A sleek black hoodie featuring a bold gold tribal-like symbol vertically aligned on the chest. The design is mirrored on both sleeves and subtly repeated on the inside of the hood, giving it a mystical, futuristic look. Perfect for streetwear or artistic fashion fans, this hoodie combines minimalism with symbolic power.', '/uploads/product_images/product-1769477104699-249680877.webp', '45.00', 'USD', 'merch', 'physical', '', 50, FALSE, '', '', NULL, '2025-07-26T18:24:19.832Z', NULL, FALSE);
INSERT INTO "products" ("id", "name", "slug", "description", "image_url", "price", "currency", "category", "product_type", "artist_name", "stock_level", "is_new_release", "cmi_product_id", "paypal_product_id", "digital_file_url", "created_at", "updated_at", "archived") VALUES (3, 'Izuran Hoodie Up', 'izuran-hoodie-up', 'This variant of the black hoodie showcases the same glowing gold emblem, now with the hood pulled up—enhancing its mysterious and immersive aesthetic. The golden symbol illuminates more dramatically under shadowed lighting, and the full-length sleeve designs make it a standout piece for fans of dark, cyber-spiritual fashion.

', '/uploads/product_images/product-1753557649726-45546596.webp', '45.00', 'USD', 'merch', 'physical', 'Hypnokronoo', 50, FALSE, '', '', NULL, '2025-07-22T20:36:24.445Z', NULL, TRUE);

